import { Component, OnInit } from '@angular/core';
import { ToastService } from '../toast-service';
import { icons } from './data';

@Component({
  selector: 'app-materialdesign',
  templateUrl: './materialdesign.component.html',
  styleUrls: ['./materialdesign.component.scss']
})

/**
 * Materialdesign Component
 */
export class MaterialdesignComponent implements OnInit {

   // bread crumb items
   breadCrumbItems!: Array<{}>;
   icons!: Array<{}>;
   iconsCount = 0;
   newIconsCount = 0;

   constructor(public toastService: ToastService) { }

   ngOnInit(): void {
     /**
     * BreadCrumb
     */
      this.breadCrumbItems = [
       { label: 'Icons' },
       { label: 'Material Design', active: true }
     ];

     this.icons = icons;
     /**
      * Blank Icon set
      */
     this.icons.push({ name: 'blank', hex: 'f68c' });
     this.icons.forEach((icon) => {
       var item = this.getIconItem(icon, this.isNew(icon));
       document.getElementById('icons')?.appendChild(item);
    
       if (this.isNew(icon)) {
         var newItem = this.getIconItem(icon, false);
         document.getElementById('newIcons')?.appendChild(newItem);

         this.newIconsCount++;
       }
       this.iconsCount++;
     });

   }

   /***
   * change icon version
   */
  isNew(icon: any) {
    return icon.version === '5.5.55';
  }

  isDeprecated(icon: any) {
    return typeof icon.deprecated == 'undefined' ? false : icon.deprecated;
  }

  /***
   * Icon Get
   */
  getIconItem(icon: any, isNewIcon: any) {
    var div = document.createElement('div'),
      i = document.createElement('i');
    div.className = 'col-xl-3 col-lg-4 col-sm-6';
    i.className = 'mdi mdi-' + icon.name;
    div.appendChild(i);
    var span = document.createElement('span');
    span.appendChild(document.createTextNode('mdi-' + icon.name));
    div.appendChild(span);
   
    return div;
  }

  copytext(event:any){
    var element = event.target.innerHTML
    navigator.clipboard.writeText(element);
    this.toastService.show(element + ' icon Copied Successfully !!!', { classname: 'bg-success text-center text-white', delay: 5000 });
  }

  copyicon(icon:any){
    navigator.clipboard.writeText(icon);
    this.toastService.show(icon + ' icon Copied Successfully !!!', { classname: 'bg-success text-center text-white', delay: 5000 });
  }

}
<!-- Start Breadcrumbs -->
<app-breadcrumbs title="Material Design" [breadcrumbItems]="breadCrumbItems"></app-breadcrumbs>
<!-- End Breadcrumbs -->

<div class="row icon-demo-content">
  <div class="col-12">
      <div class="card">
        <app-toastss aria-live="polite" aria-atomic="true"></app-toastss>
          <div class="card-body">
              <h4 class="card-title">New Icons</h4>
              <p class="card-title-desc mb-2">Use <code>&lt;i class="mdi mdi-*-*"&gt;&lt;/i&gt;</code> class.<span class="badge bg-success">v 6.5.95</span>.</p>

              <div class="row icon-demo-content" id="newIcons" (click)="copytext($event)"></div>
          </div> <!-- end card-body -->
      </div> <!-- end card -->

      <div class="card">
          <div class="card-body">
              <h4 class="card-title mb-4">All Icons</h4>
              <div class="row icon-demo-content" id="icons" (click)="copytext($event)"></div>
          </div> <!-- end card-body -->
      </div> <!-- end card -->
  </div> <!-- end col -->
</div> <!-- end row -->

<div class="row">
  <div class="col-12">
      <div class="card">

          <div class="card-body">
              <h4 class="card-title">Size</h4>

              <div class="row icon-demo-content">
                  <div class="col-xl-3 col-lg-4 col-sm-6"  (click)="copyicon('mdi-18px')">
                      <i class="mdi mdi-18px mdi-account"></i> mdi-18px
                  </div>

                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-24px')">
                      <i class="mdi mdi-24px mdi-account"></i> mdi-24px
                  </div>

                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-36px')">
                      <i class="mdi mdi-36px mdi-account"></i> mdi-36px
                  </div>

                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-48px')">
                      <i class="mdi mdi-48px mdi-account"></i> mdi-48px
                  </div>
              </div>
          </div>
      </div>
  </div>
</div>
<!-- end row -->

<div class="row">
  <div class="col-12">
      <div class="card">

          <div class="card-body">
              <h4 class="card-title">Rotate</h4>

              <div class="row icon-demo-content">
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-45')">
                      <i class="mdi mdi-rotate-45 mdi-account"></i> mdi-rotate-45
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-90')">
                      <i class="mdi mdi-rotate-90 mdi-account"></i> mdi-rotate-90
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-135')">
                      <i class="mdi mdi-rotate-135 mdi-account"></i> mdi-rotate-135
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon(' mdi-rotate-180')">
                      <i class="mdi mdi-rotate-180 mdi-account"></i> mdi-rotate-180
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-225')">
                      <i class="mdi mdi-rotate-225 mdi-account"></i> mdi-rotate-225
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-270')">
                      <i class="mdi mdi-rotate-270 mdi-account"></i> mdi-rotate-270
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-rotate-315')">
                      <i class="mdi mdi-rotate-315 mdi-account"></i> mdi-rotate-315
                  </div>
              </div>
          </div>
      </div>
  </div>
</div>
<!-- end row -->

<div class="row">
  <div class="col-12">
      <div class="card">

          <div class="card-body">
              <h4 class="card-title">Spin</h4>

              <div class="row icon-demo-content">
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-spin')">
                      <i class="mdi mdi-spin mdi-loading"></i> mdi-spin
                  </div>
                  <div class="col-xl-3 col-lg-4 col-sm-6" (click)="copyicon('mdi-spin')">
                      <i class="mdi mdi-spin mdi-star"></i> mdi-spin
                  </div>
              </div>
          </div>
      </div>
  </div>
</div>
<!-- end row -->
